import {
	afterEach,
	beforeEach,
	describe,
	expect,
	it,
	type Mock,
	vi,
} from "vitest";
import * as Builder from "../builder.js";
import { ExecutionError, RateLimitError } from "../error.js";
import { getPacerState } from "../pacer_internal.js";
import * as Schema from "../schema.js";
import { Worker } from "../worker.js";
import { createSyncCapability } from "./sync.js";

describe("Worker.sync", () => {
	let stdoutSpy: Mock<typeof process.stdout.write>;

	beforeEach(() => {
		stdoutSpy = vi
			.spyOn(process.stdout, "write")
			.mockImplementation(() => true);
	});

	afterEach(() => {
		vi.restoreAllMocks();
	});

	describe("Schema.relation", () => {
		it("creates a relation property configuration", () => {
			const relationProp = Schema.relation("projects");

			expect(relationProp).toEqual({
				type: "relation",
				relatedDatabaseKey: "projects",
				config: { twoWay: false },
			});
		});
	});

	describe("Builder.relation", () => {
		it("creates a relation reference from a primary key", () => {
			const value = Builder.relation("project-123");

			expect(value).toEqual({ type: "primaryKey", value: "project-123" });
		});

		it("can be used to build relation arrays", () => {
			const value = [
				Builder.relation("project-123"),
				Builder.relation("project-456"),
			];

			expect(value).toEqual([
				{ type: "primaryKey", value: "project-123" },
				{ type: "primaryKey", value: "project-456" },
			]);
		});
	});

	describe("SyncedObject with relation properties", () => {
		it("allows relation values in synced objects", async () => {
			const worker = new Worker();
			const tasks = worker.database("tasks", {
				type: "managed",
				initialTitle: "Tasks",
				primaryKeyProperty: "Task ID",
				schema: {
					properties: {
						"Task ID": Schema.title(),
						Project: Schema.relation("projects"),
					},
				},
			});

			const capability = createSyncCapability("tasksSync", {
				database: tasks,
				execute: async () => ({
					changes: [
						{
							type: "upsert",
							key: "task-1",
							properties: {
								"Task ID": Builder.title("TASK-001"),
								Project: [Builder.relation("project-123")],
							},
						},
						{
							type: "upsert",
							key: "task-2",
							properties: {
								"Task ID": Builder.title("TASK-002"),
								Project: [
									Builder.relation("project-123"),
									Builder.relation("project-456"),
								],
							},
						},
					],
					hasMore: false,
				}),
			});

			expect(capability._tag).toBe("sync");
			expect(capability.config.databaseKey).toBe("tasks");
		});
	});

	describe("pacer local fallback", () => {
		it("seeds pacer state from declarations when runtime context has no pacers", async () => {
			const worker = new Worker();
			const db = worker.database("test", {
				type: "managed",
				initialTitle: "Test",
				primaryKeyProperty: "ID",
				schema: { properties: { ID: Schema.title() } },
			});
			const pacer = worker.pacer("myApi", {
				allowedRequests: 10,
				intervalMs: 1000,
			});

			let pacerWaitCalled = false;
			const capability = createSyncCapability(
				"testSync",
				{
					database: db,
					execute: async () => {
						await pacer.wait();
						pacerWaitCalled = true;
						return { changes: [], hasMore: false };
					},
				},
				[{ key: "myApi", config: { allowedRequests: 10, intervalMs: 1000 } }],
			);

			// No runtimeContext → no pacers from server → should fall back to declarations
			await capability.handler(undefined, { concreteOutput: true });

			expect(pacerWaitCalled).toBe(true);
			const state = getPacerState();
			expect(state.pacers.myApi).toBeDefined();
			expect(state.pacers.myApi?.allowedRequests).toBe(10);
			expect(state.pacers.myApi?.intervalMs).toBe(1000);
		});

		it("uses server-provided pacers when available", async () => {
			const worker = new Worker();
			const db = worker.database("test", {
				type: "managed",
				initialTitle: "Test",
				primaryKeyProperty: "ID",
				schema: { properties: { ID: Schema.title() } },
			});
			const pacer = worker.pacer("myApi", {
				allowedRequests: 10,
				intervalMs: 1000,
			});

			let pacerWaitCalled = false;
			const capability = createSyncCapability(
				"testSync",
				{
					database: db,
					execute: async () => {
						await pacer.wait();
						pacerWaitCalled = true;
						return { changes: [], hasMore: false };
					},
				},
				[{ key: "myApi", config: { allowedRequests: 10, intervalMs: 1000 } }],
			);

			// Server provides apportioned budget (e.g., 5 instead of 10)
			await capability.handler(
				{
					pacers: {
						myApi: {
							lastScheduledAtMs: 0,
							allowedRequests: 5,
							intervalMs: 1000,
						},
					},
				},
				{ concreteOutput: true },
			);

			expect(pacerWaitCalled).toBe(true);
			// Should use server-provided value, not the declaration
			expect(getPacerState().pacers.myApi?.allowedRequests).toBe(5);
		});
	});

	describe("handler output envelope", () => {
		it("wraps successful result in success envelope", async () => {
			const worker = new Worker();
			const db = worker.database("test", {
				type: "managed",
				initialTitle: "Test",
				primaryKeyProperty: "ID",
				schema: {
					properties: {
						ID: Schema.title(),
					},
				},
			});

			const capability = createSyncCapability("testSync", {
				database: db,
				execute: async () => ({
					changes: [],
					hasMore: false,
				}),
			});

			await capability.handler();

			expect(stdoutSpy).toHaveBeenCalledWith(
				`\n<__notion_output__>${JSON.stringify({ _tag: "success", value: { changes: [], hasMore: false, nextUserContext: undefined, nextPacerStates: {} } })}</__notion_output__>\n`,
			);
		});

		it("wraps error in error envelope", async () => {
			const worker = new Worker();
			const db = worker.database("test", {
				type: "managed",
				initialTitle: "Test",
				primaryKeyProperty: "ID",
				schema: {
					properties: {
						ID: Schema.title(),
					},
				},
			});

			const capability = createSyncCapability("errorSync", {
				database: db,
				execute: async () => {
					throw new Error("sync failed");
				},
			});

			await expect(capability.handler()).rejects.toThrow(ExecutionError);

			expect(stdoutSpy).toHaveBeenCalledWith(
				expect.stringContaining(`"_tag":"error"`),
			);
			expect(stdoutSpy).toHaveBeenCalledWith(
				expect.stringContaining(`"name":"ExecutionError"`),
			);
		});

		it("wraps RateLimitError in error envelope with _tag rate_limit", async () => {
			const worker = new Worker();
			const db = worker.database("test", {
				type: "managed",
				initialTitle: "Test",
				primaryKeyProperty: "ID",
				schema: {
					properties: {
						ID: Schema.title(),
					},
				},
			});

			const capability = createSyncCapability("rateLimitSync", {
				database: db,
				execute: async () => {
					throw new RateLimitError();
				},
			});

			await expect(capability.handler()).rejects.toThrow(RateLimitError);

			expect(stdoutSpy).toHaveBeenCalledWith(
				expect.stringContaining(`"_tag":"rate_limit"`),
			);
			expect(stdoutSpy).toHaveBeenCalledWith(
				expect.stringContaining(`"name":"RateLimitError"`),
			);
		});

		it("includes retryAfter in rate_limit error envelope when provided", async () => {
			const worker = new Worker();
			const db = worker.database("test", {
				type: "managed",
				initialTitle: "Test",
				primaryKeyProperty: "ID",
				schema: {
					properties: {
						ID: Schema.title(),
					},
				},
			});

			const capability = createSyncCapability("rateLimitSync", {
				database: db,
				execute: async () => {
					throw new RateLimitError({ retryAfter: 30 });
				},
			});

			await expect(capability.handler()).rejects.toThrow(RateLimitError);

			const output = stdoutSpy.mock.calls
				.map((call) => String(call[0]))
				.find((s) => s.includes(`"_tag":"rate_limit"`)) as string;
			const parsed = JSON.parse(
				output.replace(
					/\n<__notion_output__>(.*)<\/__notion_output__>\n/,
					"$1",
				),
			);
			expect(parsed).toEqual({
				_tag: "error",
				error: {
					_tag: "rate_limit",
					name: "RateLimitError",
					message:
						"Error during worker execution: Rate limited by external API",
					retryAfter: 30,
				},
			});
		});

		it("wraps RateLimitError without retryAfter correctly", async () => {
			const worker = new Worker();
			const db = worker.database("test", {
				type: "managed",
				initialTitle: "Test",
				primaryKeyProperty: "ID",
				schema: {
					properties: {
						ID: Schema.title(),
					},
				},
			});

			const capability = createSyncCapability("rateLimitSync", {
				database: db,
				execute: async () => {
					throw new RateLimitError();
				},
			});

			await expect(capability.handler()).rejects.toThrow(RateLimitError);

			const output = stdoutSpy.mock.calls
				.map((call) => String(call[0]))
				.find((s) => s.includes(`"_tag":"rate_limit"`)) as string;
			const parsed = JSON.parse(
				output.replace(
					/\n<__notion_output__>(.*)<\/__notion_output__>\n/,
					"$1",
				),
			);
			expect(parsed.error.retryAfter).toBeUndefined();
		});

		it("emits sync output with key and default targetDatabaseKey", async () => {
			const worker = new Worker();
			const tasks = worker.database("tasks", {
				type: "managed",
				initialTitle: "Tasks",
				primaryKeyProperty: "Name",
				schema: {
					properties: {
						Name: Schema.title(),
					},
				},
			});

			const capability = createSyncCapability("tasksSync", {
				database: tasks,
				execute: async () => ({
					changes: [
						{
							type: "upsert" as const,
							key: "task-1",
							properties: {
								Name: Builder.title("Write docs"),
							},
						},
						{
							type: "delete" as const,
							key: "task-2",
						},
					],
					hasMore: false,
				}),
			});

			await capability.handler();

			expect(stdoutSpy).toHaveBeenCalledWith(
				`\n<__notion_output__>${JSON.stringify({
					_tag: "success",
					value: {
						changes: [
							{
								type: "upsert",
								key: "task-1",
								properties: {
									Name: Builder.title("Write docs"),
								},
								targetDatabaseKey: "tasks",
							},
							{
								type: "delete",
								key: "task-2",
								targetDatabaseKey: "tasks",
							},
						],
						hasMore: false,
						nextUserContext: undefined,
						nextPacerStates: {},
					},
				})}</__notion_output__>\n`,
			);
		});
	});
});
